async function run() {
  const slugs = Object.keys(bios);
  console.log(`Expanding ${slugs.length} artist bios...`);
  for (const slug of slugs) {
    const result = await sql`UPDATE artists SET bio = ${bios[slug]} WHERE slug = ${slug} RETURNING name`;
    if (result.length) {
      const wordCount = bios[slug].split(/\s+/).filter(Boolean).length;
      console.log(`  ✓ ${result[0].name} (~${wordCount} words)`);
    } else {
      console.log(`  ✗ Not found: ${slug}`);
    }
  }
  console.log('Done.');
  process.exit(0);
}

run().catch(e => { console.error(e.message); process.exit(1); });
